  ('diplomatic-0471a791-moex-00533', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-110-bf235e6a', 'sub-diplomatic-0471a791-05', NULL, 'single_choice', '半島電視台是一家以卡達首都杜哈為基地的國際電視媒體，關於它的經營，下列敘述何者正確？', '["提供不同於西方媒體的「泛阿拉伯觀點」", "新聞走向聽命於阿拉伯世界的宗教激進團體", "尚未成立中文網站", "其節目或報導並不會碰觸伊斯蘭世界的禁忌議題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:17+00:00", "source_pdf_sha1": "66532e967a5b", "answer_pdf_sha1": "b80cfb7f05e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00534', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-110-bf235e6a', 'sub-diplomatic-0471a791-05', NULL, 'single_choice', '關於國際間的「數位落差」現象，下列敘述何者正確？', '["非洲國家是全球「數位落差」問題最輕微的", "經濟條件差的國家，數位化發展明顯被邊緣化", "國際之間對弭平「數位落差」問題，並無討論，更無作為", "「數位落差」並非跨國治理的焦點，不足以構成問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:17+00:00", "source_pdf_sha1": "66532e967a5b", "answer_pdf_sha1": "b80cfb7f05e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00535', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-110-bf235e6a', 'sub-diplomatic-0471a791-05', NULL, 'single_choice', '以世界體系理論為基礎的國際資訊流通，下列敘述何者正確？', '["實力對等國家之間的新聞資訊流通也較為對等", "實力不對等的國家之間不會有任何新聞資訊流通", "惟有當原先實力不對等之國家轉變成實力對等之國家，兩國間之新聞資訊流通才可能發生", "新聞資訊可順暢且毫無障礙地流通於任何國家之間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:17+00:00", "source_pdf_sha1": "66532e967a5b", "answer_pdf_sha1": "b80cfb7f05e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
