  ('diplomatic-0471a791-moex-00541', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-110-bf235e6a', 'sub-diplomatic-0471a791-05', NULL, 'single_choice', '社群媒體平台是新興的國際傳播媒介，有關社群媒體平台，下列敘述何者錯誤？', '["Twitter在2020年6月，以「高度參與假訊息的傳播」為由，移除了15萬個吹捧中國大陸的帳號", "美國前總統川普因發言內容不當，遭到Twitter、Facebook、YouTube停權或封鎖", "2021年初，YouTube以傳遞錯誤內容為由移除了近三千個帳號", "為了處理內容爭議，Facebook成立監督委員會（TheOversightBoard），該委員會得對使用者的 帳號予以停權處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:17+00:00", "source_pdf_sha1": "66532e967a5b", "answer_pdf_sha1": "b80cfb7f05e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL)
